/**
 * Notification model and related types.
 *
 * All notification data flows through the EventBus. Services emit domain
 * events (order:created, user:updated, etc.), and the NotificationService
 * listens, builds NotificationPayload objects, and dispatches them through
 * registered NotificationAdapters (email, webhook, in-app, etc.).
 */

/**
 * Supported notification channels. Each channel corresponds to a
 * NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'in-app' | 'webhook';

/**
 * Categorises the reason a notification was sent.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/**
 * Channel-agnostic payload that adapters receive.
 * Adapters decide how to render / deliver this for their channel.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  metadata?: Record<string, string>;
}

/**
 * A persisted notification record (after delivery attempt).
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  status: 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, string>;
}

/**
 * NotificationAdapter — interface that all notification channel adapters must implement.
 *
 * Architecture constraint: Every delivery channel (email, webhook, in-app, SMS, etc.)
 * is represented by an adapter that implements this interface. The NotificationService
 * dispatches payloads to the appropriate adapter based on the payload's `channel` field.
 *
 * To add a new channel:
 * 1. Add the channel name to NotificationChannel in src/models/notification.ts.
 * 2. Create an adapter class in src/adapters/ that implements NotificationAdapter.
 * 3. Register the adapter with NotificationService via registerAdapter().
 */

import type { NotificationPayload, NotificationChannel } from '../models/notification.js';

/**
 * Result returned by an adapter after attempting delivery.
 */
export interface DeliveryResult {
  success: boolean;
  /** Human-readable error message when success is false. */
  error?: string;
}

/**
 * Contract that all notification adapters must fulfil.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Deliver a notification payload.
   * Must not throw — return a DeliveryResult with success: false on failure.
   */
  send(payload: NotificationPayload): Promise<DeliveryResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel. In production this
 * would integrate with an SMTP service or transactional email API (SendGrid,
 * SES, etc.). The current implementation is a stub that logs delivery and
 * records sent messages in memory for testing.
 */

import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import type { NotificationPayload, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Record of an email that was "sent" (stored in memory).
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';

  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   *
   * Stub implementation — stores the email in memory and returns success.
   * Replace the body of this method with real SMTP / API integration.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    try {
      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

      const email: SentEmail = {
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      };
      this.sentEmails.push(email);

      return { success: true };
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all emails sent through this adapter (useful for testing).
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — orchestrates notification delivery in response to
 * domain events received via the EventBus.
 *
 * Architecture:
 *   EventBus ──▶ NotificationService ──▶ NotificationAdapter(s)
 *
 * All cross-service communication flows through the EventBus (event-driven
 * pattern). The NotificationService subscribes to domain events, builds
 * channel-agnostic NotificationPayloads, and dispatches them to the
 * registered adapter for the target channel.
 *
 * Constraints for other developers:
 * - All notifications MUST originate from an EventBus event. Do NOT call
 *   sendNotification() from outside this service.
 * - To add a new notification trigger, subscribe to the relevant event in
 *   registerHandlers() and build a payload.
 * - To add a new delivery channel, implement NotificationAdapter and
 *   register it via registerAdapter().
 *
 * Depends on:
 * - EventBus (event system) — sole source of notification triggers
 * - NotificationAdapter implementations — delivery channels
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationChannel,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events on the EventBus.
   * All notification triggers are wired here — this is the single place
   * where events are mapped to notifications.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      notificationType: 'order_confirmation',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      notificationType: 'order_status_update',
      metadata: { orderId: event.order.id },
    });
  }

  /**
   * Build a Notification record and attempt delivery via the appropriate adapter.
   * If no adapter is registered for the channel, the notification is still
   * recorded (with status 'sent') for backwards compatibility and testing.
   */
  private sendNotification(payload: NotificationPayload): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      notificationType: payload.notificationType,
      status: 'sent',
      sentAt: new Date(),
      metadata: payload.metadata,
    };

    const adapter = this.adapters.get(payload.channel);
    if (adapter) {
      // Fire-and-forget — adapter.send() must not throw per the interface contract.
      void adapter.send(payload).then((result) => {
        if (!result.success) {
          notification.status = 'failed';
          this.logger.error(
            `Adapter delivery failed for ${notification.id}: ${result.error ?? 'unknown'}`,
          );
        }
      });
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} to ${payload.recipient}`);
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

